data.content:
MSTest **does** have comparison assertions (added in MSTest 3.x). Here's what to use:

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

Here's how you'd apply them to your `ScoreCalculator`:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calc.CalculatePercentage(7, 10);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_BelowMax_IsGreaterThanZero()
    {
        var result = _calc.NormalizeScore(50, 200);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150, 100);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(() => _calc.CalculatePercentage(0, 0));
    }
}
```

**Key comparison assertions summary:**

| Assertion | Meaning |
|-----------|---------|
| `Assert.IsGreaterThan(bound, actual)` | actual > bound |
| `Assert.IsLessThan(bound, actual)` | actual < bound |
| `Assert.IsInRange(actual, low, high)` | low ≤ actual ≤ high |

These produce much better failure messages than `Assert.IsTrue(x > 0)` — on failure they'll show the actual value and the bound that was violated.
